return [{ json: {
  team_member: 'Alex Chen',
  role: 'Senior Frontend Engineer',
  manager_role: 'Head of Product',
  last_meeting_date: '2026-07-07',
  last_meeting_summary: 'Alex mentioned feeling stretched across too many projects. We agreed to reduce to 2 active work streams. Raised a concern about lack of design specs before sprint planning.',
  recent_work: [
    { item: 'Led recurring tasks frontend — completed and in QA', type: 'delivery' },
    { item: 'Refactored TaskList component (PR-1851) — performance improvement', type: 'quality' },
    { item: 'Raised PR review process concerns in team channel', type: 'process' }
  ],
  context: {
    current_sprint_status: 'On track for recurring tasks QA sign-off',
    career_goal: 'Move to Staff Engineer within 18 months',
    known_challenges: 'Overloaded; needs clearer priorities from PM side before sprint',
    team_dynamics: 'Mentoring junior FE; doing well but taking extra time'
  },
  topics_to_discuss: [
    'Recurring tasks QA — any blockers before sign-off?',
    'Design spec process improvement — concrete steps',
    'Mentorship load — is it sustainable?'
  ]
} }];

const ctx = $input.first().json;
const recentWork = ctx.recent_work.map(w => `  [${w.type.toUpperCase()}] ${w.item}`).join('
');
const topics = ctx.topics_to_discuss.map(t => `  • ${t}`).join('
');
const system = `You are an executive coach and people manager advisor. You help managers prepare for high-quality 1:1 conversations. You generate: a concise agenda, coaching questions that surface what matters to the individual, recognition moments to acknowledge, and blockers for the manager to address. Be specific, not generic. Return ONLY valid JSON.`;
const user = `Prepare a 1:1 meeting agenda for my meeting with ${ctx.team_member} (${ctx.role}).

Last meeting (${ctx.last_meeting_date}): ${ctx.last_meeting_summary}

Recent work:
${recentWork}

Context:
  Career goal: ${ctx.context.career_goal}
  Known challenges: ${ctx.context.known_challenges}
  Team dynamics: ${ctx.context.team_dynamics}
  Sprint status: ${ctx.context.current_sprint_status}

Topics I want to cover:
${topics}

Return JSON:
{
  "opening_check_in": "string — a warm, specific opening question (not 'how are you')",
  "agenda_items": [
    {
      "topic": "string",
      "type": "delivery|coaching|career|process|recognition",
      "suggested_questions": ["string"],
      "manager_action_before": "string|null"
    }
  ],
  "recognition_moment": "string — specific acknowledgement of recent work",
  "manager_commitments_to_follow_up": ["string"],
  "coaching_theme": "string — the overarching coaching opportunity this 1:1"
}`;
return [{ json: { ctx, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare 1:1 Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.agenda_items || !Array.isArray(parsed.agenda_items)) return [{ json: { _error: true, reason: 'Missing agenda_items' } }];
return [{ json: { _error: false, prep: parsed, ctx: upstream.ctx, meta: { team_member: upstream.ctx.team_member, generated_at: new Date().toISOString() } } }];
